+    try cache.put(2, 200);
+
+    cache.cacheClear();
+
+    try std.testing.expectEqual(@as(?i32, null), cache.get(1));
+    try std.testing.expectEqual(@as(?i32, null), cache.get(2));
+    try std.testing.expectEqual(@as(usize, 0), cache.cacheInfo().currsize);
+}

