+/// For floats, uses banker's rounding (round half to even)
 pub fn pyRound(value: anytype) i64 {
     const T = @TypeOf(value);
     const info = @typeInfo(T);
     if (info == .int or info == .comptime_int) {
         return @as(i64, @intCast(value));
